namespace sv_2eec06155a674ff7bf19ce9a86722136.Models;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

using sv_2eec06155a674ff7bf19ce9a86722136.Models;

namespace sv_2eec06155a674ff7bf19ce9a86722136.Services;

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

using sv_2eec06155a674ff7bf19ce9a86722136.Models;

namespace sv_2eec06155a674ff7bf19ce9a86722136.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId;

    public MockChatService()
    {
        _channels = new List<Channel>
        {
            new(1, "general", "General discussion and announcements", 3),
            new(2, "engineering", "Engineering team collaboration", 1),
            new(3, "design", "Design reviews and feedback", 0),
            new(4, "random", "Off-topic conversations and fun stuff", 5),
            new(5, "devops", "Infrastructure and deployment topics", 0),
        };

        var now = DateTime.UtcNow;
        _messages = new List<Message>
        {
            // #general
            new(1, 1, "Alice", "Hey everyone! Welcome to the new team chat 🎉", now.AddHours(-8), null, new List<Reaction>
            {
                new("🎉", new List<string> { "Bob", "Carol", "Dave" }),
                new("👍", new List<string> { "Eve", "Frank" }),
            }),
            new(2, 1, "Bob", "Thanks Alice! This looks great. When's the kickoff meeting?", now.AddHours(-7.5), null, new List<Reaction>()),
            new(3, 1, "Carol", "The kickoff meeting is scheduled for Thursday at 2pm. I'll send a calendar invite shortly.", now.AddHours(-7), 2, new List<Reaction>
            {
                new("👍", new List<string> { "Bob" }),
            }),
            new(4, 1, "Dave", "Looking forward to it! Do we have an agenda yet?", now.AddHours(-6.5), 2, new List<Reaction>()),
            new(5, 1, "Alice", "I just shared the Q3 roadmap document in the shared drive. Please review before Thursday.", now.AddHours(-5), null, new List<Reaction>
            {
                new("👀", new List<string> { "Bob", "Carol" }),
            }),
            new(6, 1, "Frank", "Just reviewed it — looks solid! A few comments on the timeline though.", now.AddHours(-4), null, new List<Reaction>()),
            new(7, 1, "Eve", "Good morning everyone! Any blockers for today?", now.AddHours(-2), null, new List<Reaction>()),
            new(8, 1, "Bob", "All clear on my end 👍", now.AddHours(-1.5), null, new List<Reaction>()),

            // #engineering
            new(9, 2, "Dave", "I've pushed the new API refactor to the feature branch. Can someone review?", now.AddHours(-6), null, new List<Reaction>
            {
                new("👀", new List<string> { "Alice" }),
            }),
            new(10, 2, "Alice", "I'll take a look after lunch. Which endpoints changed?", now.AddHours(-5.5), 9, new List<Reaction>()),
            new(11, 2, "Dave", "Mainly /api/users and /api/teams. The auth middleware was also updated.", now.AddHours(-5.3), 9, new List<Reaction>()),
            new(12, 2, "Frank", "Has anyone seen this intermittent test failure in CI? The integration tests timeout randomly.", now.AddHours(-3), null, new List<Reaction>
            {
                new("😂", new List<string> { "Dave" }),
            }),
            new(13, 2, "Eve", "Yeah, I think it's a race condition in the database setup. I filed an issue last week.", now.AddHours(-2.5), 12, new List<Reaction>
            {
                new("👍", new List<string> { "Frank" }),
            }),
            new(14, 2, "Carol", "Reminder: we're upgrading to .NET 11 this sprint. Please test your services locally first.", now.AddMinutes(-45), null, new List<Reaction>
            {
                new("🔥", new List<string> { "Dave", "Alice", "Frank" }),
            }),

            // #design
            new(15, 3, "Carol", "New mockups for the dashboard are in Figma. Link in the thread 👇", now.AddHours(-4), null, new List<Reaction>
            {
                new("❤️", new List<string> { "Alice", "Eve" }),
                new("🎉", new List<string> { "Bob" }),
            }),
            new(16, 3, "Carol", "https://figma.com/file/example — feedback welcome!", now.AddHours(-3.9), 15, new List<Reaction>()),
            new(17, 3, "Alice", "Love the new color scheme! The sidebar feels much cleaner.", now.AddHours(-3), 15, new List<Reaction>()),

            // #random
            new(18, 4, "Bob", "Anyone up for lunch at the new ramen place?", now.AddHours(-3), null, new List<Reaction>
            {
                new("🎉", new List<string> { "Dave", "Eve" }),
            }),
            new(19, 4, "Dave", "Count me in! 🍜", now.AddHours(-2.8), 18, new List<Reaction>()),
            new(20, 4, "Eve", "Did you all see the latest tech conference keynote? Mind blown 🤯", now.AddMinutes(-30), null, new List<Reaction>
            {
                new("🔥", new List<string> { "Frank", "Alice" }),
                new("👀", new List<string> { "Bob" }),
            }),

            // #devops
            new(21, 5, "Frank", "Deploying v2.4.1 to staging now. ETA 15 minutes.", now.AddHours(-1), null, new List<Reaction>()),
            new(22, 5, "Frank", "Staging deploy complete. All health checks passing ✅", now.AddMinutes(-40), null, new List<Reaction>
            {
                new("👍", new List<string> { "Carol", "Dave" }),
            }),
        };

        _nextMessageId = _messages.Max(m => m.Id) + 1;
    }

    public Task<List<Channel>> GetChannelsAsync()
    {
        return Task.FromResult(_channels.ToList());
    }

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var messages = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(messages);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var id = _nextMessageId++;
        var message = new Message(id, channelId, "You", content, DateTime.UtcNow, replyToId, new List<Reaction>());
        _messages.Add(message);
        return Task.FromResult(message);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        var replies = _messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();

        var result = new List<Message>();
        if (root != null) result.Add(root);
        result.AddRange(replies);
        return Task.FromResult(result);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var message = _messages.FirstOrDefault(m => m.Id == messageId);
        if (message != null)
        {
            var existing = message.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing != null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                message.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
            }
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
        return Task.CompletedTask;
    }
}

