            new(20, 4, "Eve", "Did you all see the latest tech conference keynote? Mind blown 🤯", now.AddMinutes(-30), null, new List<Reaction>
            {
                new("🔥", new List<string> { "Frank", "Alice" }),
                new("👀", new List<string> { "Bob" }),
            }),

