            new(21, 5, "Frank", "Deploying v2.4.1 to staging now. ETA 15 minutes.", now.AddHours(-1), null, new List<Reaction>()),
            new(22, 5, "Frank", "Staging deploy complete. All health checks passing ✅", now.AddMinutes(-40), null, new List<Reaction>
            {
                new("👍", new List<string> { "Carol", "Dave" }),
            }),
        };

        _nextMessageId = _messages.Max(m => m.Id) + 1;
    }

    public Task<List<Channel>> GetChannelsAsync()
    {
        return Task.FromResult(_channels.ToList());
    }

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var messages = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(messages);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var id = _nextMessageId++;
        var message = new Message(id, channelId, "You", content, DateTime.UtcNow, replyToId, new List<Reaction>());
        _messages.Add(message);
        return Task.FromResult(message);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        var replies = _messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();

        var result = new List<Message>();
        if (root != null) result.Add(root);
        result.AddRange(replies);
        return Task.FromResult(result);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var message = _messages.FirstOrDefault(m => m.Id == messageId);
        if (message != null)
        {
            var existing = message.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing != null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                message.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
            }
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
        return Task.CompletedTask;
    }
}

