arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_2eec06155a674ff7bf19ce9a86722136.Models
@using sv_2eec06155a674ff7bf19ce9a86722136.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<div class="chat-container">
    <!-- Sidebar -->
    <div class="chat-sidebar">
        <div class="sidebar-header">
            <h5>💬 Team Chat</h5>
        </div>
        <div class="channel-list">
            @if (_channels != null)
            {
                @foreach (var channel in _channels)
                {
                    <div class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                         @onclick="() => SelectChannelAsync(channel.Id)">
                        <span class="channel-name"># @channel.Name</span>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="badge bg-primary rounded-pill">@channel.UnreadCount</span>
                        }
                        <div class="channel-desc">@TruncateText(channel.Description, 32)</div>
                    </div>
                }
            }
        </div>
    </div>

    <!-- Main message area -->
    <div class="chat-main @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel != null)
        {
            <div class="main-header">
                <h6># @_activeChannel.Name</h6>
                <span class="header-desc">@_activeChannel.Description</span>
            </div>
            <div class="message-list" id="messageList">
                @if (_loadingMore)
                {
                    <div class="text-center p-2"><span class="spinner-border spinner-border-sm"></span> Loading…</div>
                }
                @if (_noMoreMessages)
                {
                    <div class="text-center text-muted p-2" style="font-size:.8rem;">Beginning of channel</div>
                }
                @foreach (var msg in _messages)
                {
                    <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                         @onmouseleave="() => { if (_hoveredMessageId == msg.Id) _hoveredMessageId = null; }">
                        <div class="message-meta">
                            <span class="msg-author">@msg.Author</span>
                            <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                        </div>
                        <div class="msg-content">@msg.Content</div>

                        @if (msg.Reactions.Count > 0)
                        {
                            <div class="reaction-list">
                                @foreach (var r in msg.Reactions)
                                {
                                    <span class="reaction-pill" @onclick="() => ReactAsync(msg.Id, r.Emoji)"
                                          title="@string.Join(", ", r.Users)">
                                        @r.Emoji @r.Users.Count
                                    </span>
                                }
                            </div>
                        }

                        @{ var threadCount = GetThreadReplyCount(msg.Id); }
                        @if (threadCount > 0)
                        {
                            <div class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                💬 @threadCount @(threadCount == 1 ? "reply" : "replies")
                            </div>
                        }

                        @if (_hoveredMessageId == msg.Id)
                        {
                            <div class="msg-actions">
                                <button class="btn btn-sm btn-outline-secondary" @onclick="() => OpenThreadAsync(msg.Id)">Reply</button>
                                <button class="btn btn-sm btn-outline-secondary" @onclick="() => ToggleEmojiPicker(msg.Id)">React</button>
                            </div>
                            @if (_emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in _commonEmojis)
                                    {
                                        <span class="emoji-option" @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</span>
                                    }
                                </div>
                            }
                        }
                    </div>
                }
            </div>
            <div class="message-input">
                <textarea @bind="_newMessage" @bind:event="oninput" placeholder="Type a message…"
                          @onkeydown="HandleMainKeyDown" rows="1"></textarea>
                <button class="btn btn-primary" @onclick="SendMainMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessage)">Send</button>
            </div>
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <div class="text-center">
                    <h4>Select a channel</h4>
                    <p>Pick a channel from the sidebar to start chatting</p>
                </div>
            </div>
        }
    </div>

    <!-- Thread panel -->
    @if (_threadOpen)
    {
        <div class="thread-panel">
            <div class="thread-header">
                <h6>Thread</h6>
                <button class="btn btn-sm btn-outline-secondary" @onclick="CloseThread">✕</button>
            </div>
            @if (_threadMessages != null && _threadMessages.Count > 0)
            {
                <div class="thread-root">
                    <div class="message-meta">
                        <span class="msg-author">@_threadMessages[0].Author</span>
                        <span class="msg-time">@FormatRelativeTime(_threadMessages[0].SentAt)</span>
                    </div>
                    <div class="msg-content">@_threadMessages[0].Content</div>
                </div>
                <div class="thread-replies" id="threadReplies">
                    @foreach (var reply in _threadMessages.Skip(1))
                    {
                        <div class="message-row">
                            <div class="message-meta">
                                <span class="msg-author">@reply.Author</span>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>
                        </div>
                    }
                </div>
            }
            <div class="message-input">
                <textarea @bind="_threadReply" @bind:event="oninput" placeholder="Reply in thread…"
                          @onkeydown="HandleThreadKeyDown" rows="1"></textarea>
                <button class="btn btn-primary" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(_threadReply)">Reply</button>
            </div>
        </div>
    }
</div>

@code {
    private List<Channel>? _channels;
    private List<Message> _messages = new();
    private List<Message>? _threadMessages;
    private List<ThreadSummary> _threadSummaries = new();

    private int? _activeChannelId;
    private Channel? _activeChannel;
    private bool _threadOpen;
    private int? _threadRootId;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private bool _loadingMore;
    private bool _noMoreMessages;
    private int _skip;
    private const int PageSize = 20;

    private string _newMessage = "";
    private string _threadReply = "";

    private readonly string[] _commonEmojis = { "👍", "❤️", "😂", "🎉", "👀", "🔥" };

    private IJSObjectReference? _jsModule;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./Components/Pages/Chat.razor.js");
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels?.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _noMoreMessages = false;
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _skip = _messages.Count;
        if (_messages.Count < PageSize) _noMoreMessages = true;
        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();
        ComputeThreadSummaries();
        CloseThread();
        StateHasChanged();
        await ScrollToBottom("messageList");
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingMore || _noMoreMessages || _activeChannelId == null) return;
        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count < PageSize) _noMoreMessages = true;
        _skip += older.Count;
        _messages.InsertRange(0, older);
        ComputeThreadSummaries();
        _loadingMore = false;
        StateHasChanged();
    }

    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId == null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _messages.Add(msg);
        _newMessage = "";
        StateHasChanged();
        await ScrollToBottom("messageList");
