+    const el = document.getElementById(elementId);
+    if (el) {
+        el.scrollTop = el.scrollHeight;
+    }
+}
+
+export function onScrollTop(elementId, dotNetRef) {
+    const el = document.getElementById(elementId);
+    if (el) {
+        el.addEventListener('scroll', () => {
+            if (el.scrollTop === 0) {
+                dotNetRef.invokeMethodAsync('LoadOlderMessages');
+            }
+        });
+    }
+}
